package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.expr.Expression;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;

import java.io.File;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;

public class Main {
    public static void main(String[] args) throws Exception {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source-directory>");
            System.exit(1);
        }

        String sourceDir = args[0];
        Path sourcePath = Paths.get(sourceDir);

        Files.walk(sourcePath)
            .filter(path -> path.toString().endsWith(".java"))
            .forEach(path -> {
                try {
                    transformFile(path);
                } catch (Exception e) {
                    System.err.println("Error processing " + path + ": " + e.getMessage());
                    e.printStackTrace();
                }
            });

        System.out.println("Transformation complete.");
    }

    private static void transformFile(Path filePath) throws Exception {
        CompilationUnit cu = StaticJavaParser.parse(filePath);

        new getClassInfoFixVisitor().visit(cu, null);

        Files.writeString(filePath, cu.toString());
        System.out.println("Transformed: " + filePath);
    }

    static class getClassInfoFixVisitor extends VoidVisitorAdapter<Void> {
        @Override
        public void visit(MethodCallExpr methodCallExpr, Void arg) {
            super.visit(methodCallExpr, arg);

            if ("getClassInfo".equals(methodCallExpr.getNameAsString())) {
                List<Expression> arguments = methodCallExpr.getArguments();
                if (arguments.size() == 1) {
                    Expression arg = arguments.get(0);
                    if (arg instanceof MethodCallExpr) {
                        MethodCallExpr innerCall = (MethodCallExpr) arg;
                        if ("singleton".equals(innerCall.getNameAsString()) &&
                            "Collections".equals(innerCall.getScope().map(Object::toString).orElse(""))) {
                            List<Expression> innerArgs = innerCall.getArguments();
                            if (innerArgs.size() == 1) {
                                methodCallExpr.setArgument(0, innerArgs.get(0).clone());
                            }
                        }
                    }
                }
            }
        }
    }
}

